// ROLLUP_NO_REPLACE 
 const _20250604Liaetmoi = "{\"parsed\":{\"_path\":\"/fr/20250604-liaetmoi\",\"_dir\":\"fr\",\"_draft\":false,\"_partial\":false,\"_locale\":\"\",\"title\":\"Un an et plus avec l'intelligence artificielle : entre gains de productivité, devoirs de mathématiques et risque de paresse mentale\",\"description\":\"Après plus d'un an d'utilisation, Jean Luc Houédanou revient sur les avantages et les inconvénients dans l'IA, dans sa vie quotidienne, incluant les devoirs de Mathématiques de sa nièce.\",\"image\":\"/images/articles/niece.png\",\"createdAt\":\"2025-06-04\",\"id\":\"2025-06-04T00:00:00.000Z\",\"keywords\":\"IA, vie quotidienne, devoirs, Mathématiques, technologie, développement personnel, productivité, assistante IA, Claude 4 Sonnet\",\"summary\":\"Ce billet raconte comment l'IA a influencé ma vie quotidienne, y compris les devoirs de Mathématiques de ma nièce.\",\"body\":{\"type\":\"root\",\"children\":[{\"type\":\"element\",\"tag\":\"h1\",\"props\":{\"id\":\"un-an-et-plus-avec-lintelligence-artificielle-entre-gains-de-productivité-devoirs-de-mathématiques-et-risque-de-paresse-mentale\"},\"children\":[{\"type\":\"text\",\"value\":\"Un an et plus avec l'intelligence artificielle : entre gains de productivité, devoirs de mathématiques et risque de paresse mentale\"}]},{\"type\":\"element\",\"tag\":\"iframe\",\"props\":{\"width\":\"100%\",\"height\":315,\"src\":\"https://www.youtube.com/embed/-NsSPJ8dTfI\",\"title\":\"YouTube video player\",\"frameBorder\":\"0\",\"allow\":\"accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share\",\"allowFullScreen\":true},\"children\":[]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Après plus d'un an d'utilisation quasi quotidienne de l'intelligence artificielle, j'avais envie de partager mon retour d'expérience.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Voici les avantages et les inconvénients que j'ai constatés — entre étonnements, galères, et petites victoires du quotidien.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"lia-et-les-devoirs-de-mathématiques-de-ma-nièce\"},\"children\":[{\"type\":\"text\",\"value\":\"L'IA et les devoirs de Mathématiques de ma nièce\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ma nièce vient de décrocher son CEPE avec 137 points sur 170, bien que, comme son tonton à son âge (et bien après), elle ait de grosses difficultés avec les maths.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"C'est là que ChatGPT entre en scène.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Grâce à son mode vocal, il explique souvent les choses mieux que moi (je l'avoue sans honte). Par exemple, j'avais oublié comment faire une division posée ou vérifier un calcul avec la preuve par 9… L'IA, elle, s'en sort très bien.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"On envisage donc de lui prendre un abonnement ChatGPT pour son entrée en 6e, parce qu'à ce stade, les maths deviennent plus costauds, et avoir un assistant patient, clair et disponible 24h/24, c'est un vrai plus.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"coder-avec-lia-est-un-plaisir\"},\"children\":[{\"type\":\"text\",\"value\":\"Coder avec l'IA est un plaisir\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Pendant longtemps, j'ai résisté. GitHub Copilot, WindSurf, Cursor… très peu pour moi. Je code principalement en PHP, un peu en JavaScript et Vue.js — React et Angular ne m'ont jamais vraiment séduit.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"J'avais peur que l'IA me rende mauvais, me propose des solutions toutes faites et m'éloigne encore plus des subtilités des langages que je maîtrise imparfaitement.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Et puis j'ai découvert Claude.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"En l'utilisant de manière réfléchie, j'ai compris que l'IA pouvait devenir une véritable alliée. Résultat : je code plus vite, je débugge mieux, et j'identifie des solutions auxquelles je n'aurais pas pensé seul.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Par exemple, j'ai récemment développé un site en Vue.js, avec des animations GSAP liées au scroll. Avant, j'aurais mis 2 semaines. Là, en 3 jours, c'était plié.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"J'ai également utilisé Cursor pour améliorer un peu \"},{\"type\":\"element\",\"tag\":\"a\",\"props\":{\"href\":\"https://jhouedanou.github.io/projectfatloss/\",\"rel\":[\"nofollow\"]},\"children\":[{\"type\":\"text\",\"value\":\"Project Fat Loss\"}]},{\"type\":\"text\",\"value\":\", mon application de suivi fitness. Cursor m'a aidé à optimiser le code, à corriger des bugs, et même à ajouter des fonctionnalités que je n'avais pas envisagées.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais attention : l'IA n'est pas (encore) autonome. Elle a besoin de notre vigilance. Claude et Cursor, par exemple, peuvent parfois se tromper lourdement.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Un jour, dans un élan de flemme assumée (en même temps, on était dimanche), je lui ai demandé de corriger un souci de timing dans une animation pendant que j'allais faire un peu de sport. À mon retour… le scroll ne marchait plus, les animations partaient dans tous les sens, et une bonne partie de mon code avait été réécrite.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Depuis, j'ai retenu la leçon et ne lui délègue plus de corrections sans surveillance. Dans le même état d'esprit, je n'utilise pas vraiment l'IA en mode \\\"agent\\\" pour coder. Je préfère lui poser des questions précises, lui demander de m'aider à trouver des solutions, ou de me suggérer des améliorations.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Ça me permet de garder le contrôle sur mon code tout en profitant de l'aide précieuse qu'elle peut apporter (sans compter que cela me permet de mieux comprendre les solutions proposées et d'apprendre en même temps).\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"lia-et-les-envois-de-mails\"},\"children\":[{\"type\":\"text\",\"value\":\"L'IA et les envois de mails\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Honnêtement, je ne me souviens plus de la dernière fois où j'ai rédigé un e-mail sans aide. Pour mes échanges professionnels comme personnels, l'IA me fait gagner un temps fou.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Elle reformule, corrige, clarifie mes idées, et réduit drastiquement les fautes d'orthographe.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"J'utilise principalement les outils de rédaction de Google Workspace, sûrement boostés par Gemini. Ils sont particulièrement efficaces pour les messages longs ou complexes.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Bien sûr, ça peut lisser un peu la touche personnelle, mais en contrepartie, les messages sont clairs, précis et bien structurés.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"et-la-vidéo-dans-tout-ça\"},\"children\":[{\"type\":\"text\",\"value\":\"Et la vidéo dans tout ça ?\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je ne sais pas, je n'ai pas essayé et je ne suis pas sûr de vouloir essayer. Mais je suis curieux de voir comment l'IA pourrait m'aider dans ce domaine à l'avenir.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"À vrai dire, je suis peut-être l'une des rares personnes que l'évolution des IA génératrices de vidéos horrifie un peu. Il y a quelque chose de troublant dans cette capacité à créer du contenu visuel si réaliste qu'il devient difficile de distinguer le vrai du faux.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Entre les deepfakes de plus en plus convaincants et la possibilité de générer n'importe quelle scène imaginable, on entre dans un territoire où la frontière entre réalité et fiction s'estompe dangereusement.\"}]},{\"type\":\"element\",\"tag\":\"h2\",\"props\":{\"id\":\"mais-attention-à-la-paresse-mentale-ie-rédaction-assistée\"},\"children\":[{\"type\":\"text\",\"value\":\"Mais attention à la paresse mentale (i.e rédaction assistée)\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"L'IA bouleverse nos habitudes, optimise notre travail, et peut même nous aider à mieux apprendre. Elle est rapide, accessible, et souvent bluffante d'efficacité.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais elle peut aussi nous rendre paresseux. On a tendance à lui déléguer trop de tâches, et parfois on oublie de réfléchir par nous-mêmes. C'est un peu comme si on laissait notre cerveau en veille.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Je me suis récemment surpris à écrire un texte assez inspiré, de manière spontanée, puis à dégainer Gemini sur mon téléphone pour le \\\"nettoyer\\\", le lisser, l'améliorer. En soi, rien de mal — c'est même pratique. Surtout qu'il fallait sur le moment répondre à des collaborateurs franchement pénibles : un texte clair, concis, sans émotions inutiles et bien tourné peut faire toute la différence.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Mais avec le recul, je me suis demandé : à quel moment ai-je arrêté de faire l'effort moi-même pour ce genre de tâches ? Ne suis je pas entrain de perdre ma spontanéité ?\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Depuis, j'ai arrêté de faire ça. Je préfère écrire mes brouillons à la main, ou au moins sans l'IA, pour garder cette étincelle créative intacte. Et surtout, pour ne pas perdre cette capacité à réfléchir, à créer, et à apprendre par moi-même.\"}]},{\"type\":\"element\",\"tag\":\"p\",\"props\":{},\"children\":[{\"type\":\"text\",\"value\":\"Jean Luc Houédanou\"}]}],\"toc\":{\"title\":\"\",\"searchDepth\":2,\"depth\":2,\"links\":[{\"id\":\"lia-et-les-devoirs-de-mathématiques-de-ma-nièce\",\"depth\":2,\"text\":\"L'IA et les devoirs de Mathématiques de ma nièce\"},{\"id\":\"coder-avec-lia-est-un-plaisir\",\"depth\":2,\"text\":\"Coder avec l'IA est un plaisir\"},{\"id\":\"lia-et-les-envois-de-mails\",\"depth\":2,\"text\":\"L'IA et les envois de mails\"},{\"id\":\"et-la-vidéo-dans-tout-ça\",\"depth\":2,\"text\":\"Et la vidéo dans tout ça ?\"},{\"id\":\"mais-attention-à-la-paresse-mentale-ie-rédaction-assistée\",\"depth\":2,\"text\":\"Mais attention à la paresse mentale (i.e rédaction assistée)\"}]}},\"_type\":\"markdown\",\"_id\":\"content:fr:20250604-Liaetmoi.md\",\"_source\":\"content\",\"_file\":\"fr/20250604-Liaetmoi.md\",\"_stem\":\"fr/20250604-Liaetmoi\",\"_extension\":\"md\",\"sitemap\":{\"loc\":\"/fr/20250604-liaetmoi\"}},\"hash\":\"97xIrHyNrP\"}";

export { _20250604Liaetmoi as default };
